module top_module(
	input clk,
	input enable,
	input reset,
	output [1:0] count);logic [1:0] count_value;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
		if (reset) count_value <= 2'b00;
		else if (enable) count_value <= count_value + 1;

	assign count = count_value;

endmodule
